import React from 'react';
import Papa from 'papaparse';
import { UploadCloud } from 'lucide-react';

const FileUploader = ({ onDataLoaded }) => {
  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    Papa.parse(file, {
      header: true, // Esto usa la primera fila (tus nombres de columnas) como llaves
      skipEmptyLines: true,
      complete: (results) => {
        console.log("Archivo procesado:", results.data.length, "filas");
        onDataLoaded(results.data); // Le avisamos a App.js que ya tenemos los datos
      },
      error: (error) => {
        console.error("Error al leer el CSV:", error);
        alert("Hubo un error al leer el archivo.");
      }
    });
  };

  return (
    <div className="flex flex-col items-center justify-center h-screen bg-[#080c14] text-white p-6">
      <div className="w-full max-w-md p-10 border-2 border-dashed border-slate-800 rounded-3xl bg-[#111827]/30 flex flex-col items-center gap-6 hover:border-blue-500/50 transition-all group">
        <div className="p-4 bg-blue-600/10 rounded-full text-blue-500 group-hover:scale-110 transition-transform">
          <UploadCloud size={48} />
        </div>
        <div className="text-center">
          <h2 className="text-xl font-black tracking-tight mb-2">Cargar Monitor Inbound</h2>
          <p className="text-sm text-slate-500">Seleccioná el reporte CSV extraído del sistema</p>
        </div>
        <label className="cursor-pointer bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-xl font-bold text-sm transition-all shadow-lg shadow-blue-900/40">
          BUSCAR ARCHIVO
          <input type="file" accept=".csv" className="hidden" onChange={handleFileUpload} />
        </label>
      </div>
    </div>
  );
};

export default FileUploader;
